{
    internal sealed class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            return ReadResponseError(doc.RootElement);
        }

        private static ResponseError ReadResponseError(JsonElement root)
        {
            string code = null, message = null, target = null;
            List<ResponseError> details = null;

            if (root.TryGetProperty("code", out var c))
                code = c.GetString();
            if (root.TryGetProperty("message", out var m))
                message = m.GetString();
            if (root.TryGetProperty("target", out var t))
                target = t.GetString();
            if (root.TryGetProperty("details", out var d) && d.ValueKind == JsonValueKind.Array)
            {
                details = new List<ResponseError>();
                foreach (var item in d.EnumerateArray())
                {
                    details.Add(ReadResponseError(item));
                }
            }

            return new ResponseError(code, message, target, default, null, details);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            if (value == null)
            {
                writer.WriteNullValue();
                return;
            }

            writer.WriteStartObject();
            if (value.Code != null)
                writer.WriteString("code", value.Code);
            if (value.Message != null)
                writer.WriteString("message", value.Message);
            if (value.Target != null)
                writer.WriteString("target", value.Target);
            if (value.InnerError != null)
            {
                writer.WritePropertyName("innererror");
                WriteInnerError(writer, value.InnerError);
            }
            if (value.Details != null && value.Details.Count > 0)
            {
                writer.WriteStartArray("details");
                foreach (var detail in value.Details)
                {
                    Write(writer, detail, options);
                }
                writer.WriteEndArray();
            }
            writer.WriteEndObject();
        }

        private static void WriteInnerError(Utf8JsonWriter writer, ResponseInnerError innerError)
        {
            writer.WriteStartObject();
            if (innerError.Code != null)
                writer.WriteString("code", innerError.Code);
            if (innerError.InnerError != null)
            {
                writer.WritePropertyName("innererror");
                WriteInnerError(writer, innerError.InnerError);
            }
            writer.WriteEndObject();
        }
    }
